import { CREATE_SAMPLE_DB, PORT, PORT_SOCKET } from '@config/environment';
import app from './app';
import { connectDatabase } from '@config/database';
import {
    initBuiltInAttendanceStatus,
    initBuiltInDeductionTypes,
    initBuiltInDepartment,
    initBuiltInEmployee,
    initBuiltInGlobalSetting,
    initBuiltInIncomeTypes,
    initBuiltInLeaveType,
    initBuiltInPosition,
    initBuiltInRoles,
    initBuiltInShift,
    initBuiltInShiftType,
    initBuiltInNikoSectors,
    initSystemAdminAccount,
    initBuiltInPermissions
} from '@common/migration/initSeedData';
import logger from '@common/utils/logger';
import { cronManager } from '@worker/cron/cron.manager';
import http from 'http';
import { socketService } from '@socket/socket.service';
import { startupManager } from '@worker/startup/startup.manager';
import { RedisAdapter } from '@common/config/redis';
import mongoose from 'mongoose';

let server: http.Server;

const bootstrap = async () => {
    try {
        await connectDatabase();
        await RedisAdapter.connect();
        await startupManager.register();

        server = http.createServer(app);

        server.listen(PORT, () => {
            logger.info(`Server running on port ${PORT}`);
        });

        socketService.setup(PORT_SOCKET);
        await cronManager.register();

    } catch (error) {
        logger.error('Server start failed', error);
        process.exit(1);
    }

    if (CREATE_SAMPLE_DB) {
        try {
            await initBuiltInRoles();
            await initSystemAdminAccount();
            await initBuiltInShiftType();
            await initBuiltInLeaveType();
            await initBuiltInAttendanceStatus();
            await initBuiltInIncomeTypes();
            await initBuiltInDeductionTypes();
            await initBuiltInGlobalSetting();
            await initBuiltInPosition();
            await initBuiltInDepartment();
            // await initBuiltInEmployee();
            await initBuiltInShift();
            await initBuiltInNikoSectors();
            await initBuiltInPermissions();
        } catch (error) {
            logger.error('Failed to initialize seed data:', error);
        }
    }
};

const shutdownProperly = (exitCode: number) => {
    Promise.resolve()
        .then(() => {
            if (server) {
                return new Promise((resolve) => {
                    server.close(() => {
                        logger.info('HTTP server closed');
                        resolve(null);
                    });
                });
            }
        })
        .then(() => socketService.close())
        .then(() => cronManager.stop())
        .then(() => RedisAdapter.disconnect())
        .then(() => mongoose.connection.close())
        .then(() => {
            logger.info('Shutdown complete, bye bye!');
            process.exit(exitCode);
        })
        .catch((err) => {
            logger.error('Error during shutdown', err);
            process.exit(1);
        });
};

process.on('uncaughtException', (err: unknown) => {
    logger.error('Uncaught exception', err);
    shutdownProperly(1);
});

process.on('unhandledRejection', (reason: unknown | null | undefined) => {
    logger.error('Unhandled Rejection at promise', reason);
    shutdownProperly(2);
});

process.on('SIGINT', () => {
    logger.info('Caught SIGINT, exiting!');
    shutdownProperly(128 + 2);
});

process.on('SIGTERM', () => {
    logger.info('Caught SIGTERM, exiting');
    shutdownProperly(128 + 15);
});

process.on('exit', () => {
    logger.info('Exiting process...');
});

bootstrap();

