import { Request, Response, NextFunction } from 'express';

/**
 * Recursively trims all string values in an object.
 * Skips properties named 'password'.
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const trimObject = (obj: any): any => {
    if (obj && typeof obj === 'object') {
        Object.keys(obj).forEach((key) => {
            if (key.toLowerCase() === 'password') {
                return;
            }
            const value = obj[key];
            if (typeof value === 'string') {
                obj[key] = value.trim();
            } else if (value && typeof value === 'object') {
                trimObject(value);
            }
        });
    }
    return obj;
};

export const trimRequest = (req: Request, res: Response, next: NextFunction) => {
    if (req.body) {
        trimObject(req.body);
    }
    if (req.query) {
        trimObject(req.query);
    }
    if (req.params) {
        trimObject(req.params);
    }
    next();
};
