import {
    ILeaveTypePayload,
    ILeaveTypes,
    ILeaveTypeFilterGetOne,
    ILeaveTypeFilter,
} from '@common/interfaces/leaveType.interface';
import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import LeaveTypeModel from './leaveType.model';
import { QueryFilter } from 'mongoose';

export class LeaveTypeService {
    public async createLeaveType(payload: ILeaveTypePayload): Promise<IApiResponse<ILeaveTypes>> {
        const exitedLeaveTypeName = await LeaveTypeModel.findOne({ name: payload.name });
        if (exitedLeaveTypeName) {
            throw new ApiError(400, 'Tên loại nghỉ phép đã tồn tại');
        }
        const exitedLeaveTypeCode = await LeaveTypeModel.findOne({ code: payload.code });
        if (exitedLeaveTypeCode) {
            throw new ApiError(400, 'Mã code của loại nghỉ phép đã tồn tại');
        }
        const newLeaveType = await LeaveTypeModel.create(payload);
        return {
            success: true,
            message: 'Tạo loại nghỉ phép thành công',
            data: newLeaveType,
        };
    }

    public async getOneLeaveType(filter: ILeaveTypeFilterGetOne): Promise<IApiResponse<ILeaveTypes>> {
        const record = await LeaveTypeModel.findOne(filter);
        if (!record) {
            return {
                success: false,
                message: 'Không tìm thấy loại nghỉ phép',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã thấy loại nghỉ phép',
            data: record,
        };
    }

    public async getLeaveTypeByFilter(filter: ILeaveTypeFilter): Promise<IPaginatedResponse<ILeaveTypes>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<ILeaveTypeFilter> = {};
        if (filter.name) {
            const name = filter.name.normalize('NFC');
            query.$or = [
                {
                    name: {
                        $regex: `.*${name}.*`,
                        $options: 'i',
                    },
                },
                {
                    code: {
                        $regex: `.*${name}.*`,
                        $options: 'i',
                    },
                },
            ];
        }
        if (filter.code) {
            query.code = {
                $regex: `.*${filter.code}.*`,
                $options: 'i',
            };
        }

        const aggregateQuery = [{ $match: query }];
        const [records, docCounter] = await Promise.all([
            LeaveTypeModel.aggregate(aggregateQuery)
                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            LeaveTypeModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách loại nghỉ phép thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getLeaveTypeById(id: string): Promise<IApiResponse<ILeaveTypes>> {
        const record = await LeaveTypeModel.findById(id);
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy Loại nghỉ phép này');
        }
        return {
            success: true,
            message: 'Đã thấy loại nghỉ phép',
            data: record,
        };
    }

    public async updateLeaveType(id: string, payload: ILeaveTypePayload): Promise<IApiResponse<ILeaveTypes>> {
        if (payload.name) {
            const exitedLeaveTypeName = await LeaveTypeModel.findOne({ name: payload.name, _id: { $ne: id } });
            if (exitedLeaveTypeName) {
                throw new ApiError(400, 'Tên loại nghỉ phép đã tồn tại');
            }
        }
        if (payload.code) {
            const exitedLeaveTypeCode = await LeaveTypeModel.findOne({ code: payload.code, _id: { $ne: id } });
            if (exitedLeaveTypeCode) {
                throw new ApiError(400, 'Mã code của loại nghỉ phép đã tồn tại');
            }
        }

        const shiftType = await LeaveTypeModel.findByIdAndUpdate(id, payload, { new: true });
        if (!shiftType) {
            throw new ApiError(400, 'Loại nghỉ phép không tồn tại');
        }
        return {
            success: true,
            message: 'Cập nhật thông tin loại nghỉ phép thành công',
            data: shiftType,
        };
    }

    public async deleteLeaveType(id: string): Promise<IApiResponse<ILeaveTypes>> {
        const shiftType = await LeaveTypeModel.findByIdAndDelete(id);
        if (!shiftType) {
            throw new ApiError(400, 'Loại nghỉ phép không tồn tại');
        }
        return {
            success: true,
            message: 'Xóa loại nghỉ phép thành công',
            data: shiftType,
        };
    }
}
