import { IEmployees } from '@common/interfaces/employee.interface';
import { IAccountStatus } from '@common/utils/enum';
import mongoose, { Schema, Types } from 'mongoose';

const EmployeesSchema: Schema = new Schema(
    {
        fullName: { type: String },
        code: { type: String },
        tamCode: { type: String },
        phone: { type: String },
        email: { type: String },
        address: { type: String },
        avatar: { type: String },
        departmentId: { type: Types.ObjectId, ref: 'Departments' },
        positionId: { type: Types.ObjectId, ref: 'Positions' },
        status: {
            type: String,
            enum: Object.values(IAccountStatus),
            default: undefined,
        },
        dateOfBirth: { type: Date },
    },
    {
        timestamps: {
            createdAt: 'createdAt',
            updatedAt: 'updatedAt',
        },
    },
);

EmployeesSchema.index(
    { departmentId: 1 },
    {
        name: 'idx_employee_departmentId',
        background: true,
    },
);

EmployeesSchema.index(
    { positionId: 1 },
    {
        name: 'idx_employee_positionId',
        background: true,
    },
);

const EmployeesModel = mongoose.model<IEmployees>('Employees', EmployeesSchema);
export default EmployeesModel;

