import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import ContractsModel from './contracts.model';
import { QueryFilter } from 'mongoose';
import { IPayroll } from '@common/interfaces/payroll.interface';
import {
    IContracts,
    IContractsFilter,
    IContractsFilterGetOne,
    IContractsPayload,
} from '@common/interfaces/contracts.interface';

export class ContractsService {
    public async createContract(payload: IContractsPayload): Promise<IApiResponse<IContracts>> {
        const newContract = await ContractsModel.create(payload);
        return {
            success: true,
            message: 'Tạo hợp đồng thành công',
            data: newContract,
        };
    }

    public async getOneContract(filter: IContractsFilterGetOne): Promise<IApiResponse<IContracts>> {
        const record = await ContractsModel.findOne(filter);
        if (!record) {
            return {
                success: false,
                message: 'Không tìm thấy hợp đồng',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã thấy hợp đồng',
            data: record,
        };
    }

    public async getContractsByFilter(filter: IContractsFilter): Promise<IPaginatedResponse<IPayroll>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IContractsFilter> = {};

        if (filter.employeeId) {
            query.employeeId = filter.employeeId;
        }
        if (filter.previousContractId) {
            query.previousContractId = filter.previousContractId;
        }
        if (filter.positionId) {
            query.positionId = filter.positionId;
        }
        if (filter.departmentId) {
            query.departmentId = filter.departmentId;
        }
        if (filter.code) {
            const code = filter.code.normalize('NFC');
            query.code = {
                $regex: `.*${code}.*`,
                $options: 'i',
            };
        }
        if (filter.status) {
            query.status = filter.status;
        }
        if (filter.name) {
            const name = filter.name.normalize('NFC');
            query.name = {
                $regex: `.*${name}.*`,
                $options: 'i',
            };
        }
        if (filter.type) {
            query.type = filter.type;
        }
        if (filter.signatoryName) {
            const signatoryName = filter.signatoryName.normalize('NFC');
            query.signatoryName = {
                $regex: `.*${signatoryName}.*`,
                $options: 'i',
            };
        }
        if (filter.workingPlace) {
            const workingPlace = filter.workingPlace.normalize('NFC');
            query.workingPlace = {
                $regex: `.*${workingPlace}.*`,
                $options: 'i',
            };
        }
        if (filter.workingTime) {
            const workingTime = filter.workingTime.normalize('NFC');
            query.workingTime = {
                $regex: `.*${workingTime}.*`,
                $options: 'i',
            };
        }

        const andQuery = [{}];
        if (filter.startDate) {
            andQuery.push({
                $expr: {
                    $gte: [{ $toDate: '$startDate' }, filter.startDate],
                },
            });
        }
        if (filter.endDate) {
            andQuery.push({
                $expr: {
                    $lte: [{ $toDate: '$endDate' }, filter.endDate],
                },
            });
        }
        query.$and = andQuery;

        if (filter.probationEndDate) {
            const startOfDay = new Date(filter.startDate);
            startOfDay.setUTCHours(0, 0, 0, 0);
            const endOfDay = new Date(filter.endDate);
            endOfDay.setUTCHours(23, 59, 59, 999);
            query.probationEndDate = {
                $gte: startOfDay,
                $lte: endOfDay,
            };
        }
        if (filter.baseSalary) {
            query.baseSalary = filter.baseSalary;
        }
        if (filter.allowance) {
            query.allowance = filter.allowance;
        }
        if (filter.probationSalaryRate) {
            query.probationSalaryRate = filter.probationSalaryRate;
        }
        if (filter.insuranceSalary) {
            query.insuranceSalary = filter.insuranceSalary;
        }

        const aggregateQuery = [{ $match: query }];
        const [records, docCounter] = await Promise.all([
            ContractsModel.aggregate(aggregateQuery)
                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            ContractsModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách hợp đồng thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

