export const createAttendanceMobileByGPS = catchAsync(async (req: Request, res: Response) => {
    const { lat, long } = req.body;
    const [gpsOfficeList, gpsRadius] = await Promise.all([
        globalSettingService.getOneGlobalSetting({ key: IGlobalSettingKey.GPS_OFFICE_LIST }),
        globalSettingService.getOneGlobalSetting({ key: IGlobalSettingKey.GPS_ATTENDANCE_RADIUS }),
    ]);

    const offices = JSON.parse(gpsOfficeList.data?.value || '[]');
    const radius = parseFloat(gpsRadius.data?.value || '100');

    const isNearOffice = offices.some((office: { lat: number; long: number }) => {
        const distance = getDistance(lat, long, office.lat, office.long);
        return distance <= radius;
    });

    if (!isNearOffice) {
        res.status(403).send('Bạn đang ở ngoài phạm vi cho phép chấm công');
        return;
    }

    const currentTime = moment().tz('Asia/Ho_Chi_Minh').toDate();
    const startOfDay = moment().tz('Asia/Ho_Chi_Minh').startOf('day').format('YYYY-MM-DD');

    if (req.users?.user?.username === 'admin') {
        res.status(403).send('Tài khoản admin không được phép chấm công');
        return;
    }

    if (req.users?.user?.employeeId) {
        const exitedAttendance = await attendancesService.getOneAttendances({
            employeeId: req.users.user.employeeId,
            date: startOfDay,
        });

        if (exitedAttendance.data?._id) {
            const checkin = new Date(exitedAttendance.data.checkin);
            const totalWorkingHours = (currentTime.getTime() - checkin.getTime()) / 1000;

            await attendancesService.updateAttendancesById(exitedAttendance.data._id.toString(), {
                checkout: currentTime,
                totalWorkingHours,
                $push: {
                    records: [currentTime],
                },
            });
        } else {
            const shift = await shiftService.getOneShift(SHIFT_DEFAULT.NAME);
            const shiftId: string = shift.data?._id?.toString();
            const userAgent = req.headers['user-agent'];
            await attendancesService.createAttendances({
                employeeId: req.users.user.employeeId,
                date: startOfDay,
                checkin: currentTime,
                records: [currentTime],
                deviceInfo: userAgent,
                ...(shiftId && { shiftId: new Types.ObjectId(shiftId) }),
            });
        }
    }

    res.status(200).send('Ghi nhận chấm công thành công');
});

