                records: [currentTime],
                deviceInfo: `FE: ${userAgent}`,
                ...(shiftId && { shiftId: new Types.ObjectId(shiftId) }),
            });
        }
    } else {
        res.status(400).send('Không tìm thấy thông tin nhân viên');
        return;
    }

    res.status(200).send('Ghi nhận chấm công thành công');
});
