import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import { PipelineStage, QueryFilter } from 'mongoose';
import {
    IAttendances,
    IAttendancesFilter,
    IAttendancesFilterGetOne,
    IAttendancesPayload,
} from '@common/interfaces/attendances.interface';
import AttendancesModel from './attendances.model';
import { IOKRQuarter } from '@common/utils/enum';
import moment from 'moment-timezone';

export class AttendancesService {
    public async createAttendances(payload: IAttendancesPayload): Promise<IApiResponse<IAttendances>> {
        const newAttendances = await AttendancesModel.create(payload);
        return {
            success: true,
            message: 'Tạo chấm công thành công',
            data: newAttendances,
        };
    }

    public async getOneAttendances(filter: IAttendancesFilterGetOne): Promise<IApiResponse<IAttendances>> {
        const record = await AttendancesModel.findOne(filter);
        if (!record) {
            return {
                success: false,
                message: 'Không tìm thấy chấm công',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã thấy chấm công',
            data: record,
        };
    }

    public async getAttendancesByFilter(filter: IAttendancesFilter): Promise<IPaginatedResponse<IAttendances>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IAttendancesFilter> = {};
        if (filter.deviceInfo) {
            const deviceInfo = filter.deviceInfo.normalize('NFC');
            query.deviceInfo = {
                $regex: `.*${deviceInfo}.*`,
                $options: 'i',
            };
        }
        if (filter.employeeId) {
            query.employeeId = filter.employeeId;
        }
        if (filter.departmentId) {
            query['employee.departmentId'] = filter.departmentId;
        }
        if (filter.shiftId) {
            query.shiftId = filter.shiftId;
        }
        if (filter.statusId) {
            query.statusId = filter.statusId;
        }
        if (filter.date) {
            query.date = filter.date;
        }

        const andQuery = [];
        if (filter.startDate)
            andQuery.push({
                $expr: {
                    $gte: [{ $toDate: '$date' }, filter.startDate],
                },
            });
        if (filter.endDate) {
            andQuery.push({
                $expr: {
                    $lte: [{ $toDate: '$date' }, filter.endDate],
                },
            });
        }
        if (andQuery.length > 0) {
            query.$and = andQuery;
        }

        if (filter.checkin) {
            const startOfDay = new Date(filter.checkin);
            startOfDay.setUTCHours(0, 0, 0, 0);
            const endOfDay = new Date(filter.checkin);
            endOfDay.setUTCHours(23, 59, 59, 999);
            query.checkin = {
                $gte: startOfDay,
                $lte: endOfDay,
            };
        }
        if (filter.checkout) {
            const startOfDay = new Date(filter.checkout);
            startOfDay.setUTCHours(0, 0, 0, 0);
            const endOfDay = new Date(filter.checkout);
            endOfDay.setUTCHours(23, 59, 59, 999);
            query.checkout = {
                $gte: startOfDay,
                $lte: endOfDay,
            };
        }
        if (filter.totalWorkingHours) {
            query.totalWorkingHours = filter.totalWorkingHours;
        }
        const aggregateQuery: PipelineStage[] = [
            {
                $lookup: {
                    from: 'employees',
                    localField: 'employeeId',
                    foreignField: '_id',
                    as: 'employee',
                },
            },
            {
                $unwind: { path: '$employee', preserveNullAndEmptyArrays: true },
            },
            { $match: query },
            { $sort: { createdAt: -1 } },
            { $skip: (page - 1) * limit },
            { $limit: limit },

            {
                $lookup: {
                    from: 'shifts',
                    localField: 'shiftId',
                    foreignField: '_id',
                    as: 'shiftId',
                },
            },
            {
                $lookup: {
                    from: 'attendance-statuses',
                    localField: 'statusId',
                    foreignField: '_id',
                    as: 'statusId',
                },
            },
            {
                $unwind: { path: '$shiftId', preserveNullAndEmptyArrays: true },
            },
            {
                $unwind: { path: '$statusId', preserveNullAndEmptyArrays: true },
            },
        ];

        const [records, docCounter] = await Promise.all([
            AttendancesModel.aggregate(aggregateQuery),
            AttendancesModel.aggregate([
                {
                    $lookup: {
                        from: 'employees',
                        localField: 'employeeId',
                        foreignField: '_id',
                        as: 'employee',
                    },
                },
                { $match: query },
                { $count: 'count' },
            ]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách chấm công thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getAttendancesById(id: string): Promise<IApiResponse<IAttendances>> {
        const record = await AttendancesModel.findById(id)
            .populate('employeeId')
            .populate('shiftId')
            .populate('statusId');
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy chấm công này');
        }
        return {
            success: true,
            message: 'Đã thấy chấm công',
            data: record,
        };
    }

    public async updateAttendancesById(id: string, payload: IAttendancesPayload): Promise<IApiResponse<IAttendances>> {
        const attendances = await AttendancesModel.findByIdAndUpdate(id, payload, { new: true });
        if (!attendances) {
            throw new ApiError(404, 'Chấm công không tồn tại');
        }
        return {
            success: true,
            message: 'Cập nhật thông tin chấm công thành công',
            data: attendances,
        };
    }

    public async deleteAttendancesById(id: string): Promise<IApiResponse<IAttendances>> {
        const attendances = await AttendancesModel.findByIdAndDelete(id);
        if (!attendances) {
            throw new ApiError(404, 'Chấm công không tồn tại');
        }
        return {
            success: true,
            message: 'Xóa chấm công thành công',
            data: attendances,
        };
    }

    public async getAttendancesRanking(filter: IAttendancesFilter): Promise<IPaginatedResponse<IAttendances>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IAttendancesFilter> = {};

        if (filter.employeeId) {
            query.employeeId = filter.employeeId;
        }
        if (filter.month && filter.year) {
            const startOfMonth = moment([filter.year, filter.month - 1]).format('YYYY-MM-DD');
            const nextMonth = moment([filter.year, filter.month - 1])
                .add(1, 'month')
                .format('YYYY-MM-DD');
            query.date = {
                $gte: startOfMonth,
                $lt: nextMonth,
            };
        }
        if (filter.quarter && filter.year) {
            let startMonth: number;
            let endMonth: number;
            let yearToUse = filter.year;
            if (filter.quarter === IOKRQuarter.QuarterOne) {
                startMonth = 1;
                endMonth = 4;
            }
            if (filter.quarter === IOKRQuarter.QuarterTwo) {
                startMonth = 4;
                endMonth = 7;
            }
            if (filter.quarter === IOKRQuarter.QuarterThree) {
                startMonth = 7;
                endMonth = 10;
            }
            if (filter.quarter === IOKRQuarter.QuarterFour) {
                startMonth = 10;
                endMonth = 1;
                yearToUse += 1;
            }
            if (startMonth && endMonth) {
                const startOfMonth = moment([filter.year, startMonth - 1]).format('YYYY-MM-DD');
                const nextMonth = moment([yearToUse, endMonth - 1]).format('YYYY-MM-DD');
                query.date = {
                    $gte: startOfMonth,
                    $lt: nextMonth,
                };
            }
        }


        const aggregateQuery: PipelineStage[] = [
            { $match: query },
            {
                $lookup: {
                    from: 'employees',
                    localField: 'employeeId',
                    foreignField: '_id',
                    as: 'employee',
                },
            },
            { $unwind: '$employee' },
            {
                $match: filter.employeeStatus ? { 'employee.status': filter.employeeStatus } : {},
            },
            {
                $match: filter.departmentId ? { 'employee.departmentId': filter.departmentId } : {},
            },
            {
                $group: {
                    _id: '$employeeId',
                    employeeId: { $first: '$employee' },
                    totalWorkingHours: { $sum: '$totalWorkingHours' },
                },
            },
        ];
        let records = await AttendancesModel.aggregate(aggregateQuery)
            .sort({ totalWorkingHours: -1 })
            .skip((page - 1) * limit)
            .limit(limit);

        records = await AttendancesModel.populate(records, [
            { path: 'employeeId.departmentId', model: 'Departments' },
            { path: 'employeeId.positionId', model: 'Positions' },
        ]);

        const docCounter = await AttendancesModel.aggregate([...aggregateQuery, { $count: 'count' }]);
        const count = docCounter[0]?.count || 0;
        return {
            data: records,
            success: true,
            message: 'Lấy danh sách ranking chấm công thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }
}

