import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { IRoleFilter, IRolePayload, IRoles } from '@common/interfaces/roles.interface';
import RolesModel from './role.model';
import { ApiError } from '@common/utils/ApiError';
import { QueryFilter } from 'mongoose';

export class RoleService {
    public async createRole(payload: IRolePayload): Promise<IApiResponse<IRoles>> {
        const exitedRoleName = await RolesModel.findOne({ name: payload.name });
        if (exitedRoleName) {
            throw new ApiError(400, 'Tên role đã tồn tại');
        }
        const exitedRoleCode = await RolesModel.findOne({ code: payload.code });
        if (exitedRoleCode) {
            throw new ApiError(400, 'Role code đã tồn tại');
        }
        const newRole = await RolesModel.create(payload);
        return {
            success: true,
            message: 'Role created successfully',
            data: newRole,
        };
    }

    public async getRoleByName(name: string): Promise<IRoles> {
        const role = await RolesModel.findOne({ name });
        return role;
    }

    public async getRoleById(id: string): Promise<IApiResponse<IRoles>> {
        const role = await RolesModel.findById(id);
        if (!role) {
            throw new ApiError(404, 'Không tìm thấy role này');
        }
        return {
            success: true,
            message: 'Đã tìm thấy role',
            data: role,
        };
    }

    public async getRoleByFilter(filter: IRoleFilter): Promise<IPaginatedResponse<IRoles>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IRoleFilter> = {};
        if (filter.name) {
            const name = filter.name.normalize('NFC');
            query.$or = [
                {
                    name: {
                        $regex: `.*${name}.*`,
                        $options: 'i',
                    },
                },
                {
                    code: {
                        $regex: `.*${name}.*`,
                        $options: 'i',
                    },
                },
            ];
        }
        if (filter.code) {
            query.code = {
                $regex: `.*${filter.code}.*`,
                $options: 'i',
            };
        }
        if (filter.status) {
            query.status = filter.status;
        }

        const aggregateQuery = [{ $match: query }];
        const [records, docCounter] = await Promise.all([
            RolesModel.aggregate(aggregateQuery)
                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            RolesModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách role thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async updateRole(roleId: string, payload: IRolePayload): Promise<IApiResponse<IRoles>> {
        if (payload.name) {
            const exitedRoleName = await RolesModel.findOne({ name: payload.name, _id: { $ne: roleId } });
            if (exitedRoleName) {
                throw new ApiError(400, 'Tên role đã tồn tại');
            }
        }
        if (payload.code) {
            const exitedRoleCode = await RolesModel.findOne({ code: payload.code, _id: { $ne: roleId } });
            if (exitedRoleCode) {
                throw new ApiError(400, 'Role code đã tồn tại');
            }
        }
        const newRole = await RolesModel.findByIdAndUpdate(roleId, payload, { new: true });
        if (!newRole) {
            throw new ApiError(400, 'Role không tồn tại');
        }
        return {
            success: true,
            message: 'Role created successfully',
            data: newRole,
        };
    }

    public async deleteRole(roleId: string): Promise<IApiResponse<IRoles>> {
        const newRole = await RolesModel.findByIdAndDelete(roleId);
        if (!newRole) {
            throw new ApiError(400, 'Role không tồn tại');
        }
        return {
            success: true,
            message: 'Role created successfully',
            data: newRole,
        };
    }
