import logger from '@common/utils/logger';
import { catchAsync } from '@common/utils/catchAsync';
import { verifyToken } from '@common/utils/token';
import { AccountRoleService } from '@modules/accountRoles/accountRole.service';
import { AccountService } from '@modules/accounts/account.service';
import { RoleService } from '@modules/roles/role.service';
import { NextFunction, Request, Response } from 'express';
import { Socket } from 'socket.io';
import { socketService } from '@socket/socket.service';
import { ApiError } from '@common/utils/ApiError';


const accountService = new AccountService();
const accountRole = new AccountRoleService();
const roleService = new RoleService();

export const authenticationMiddleware = catchAsync(
    async (req: Request, res: Response, next: NextFunction): Promise<void> => {
        const authorization = req.headers?.authorization;
        if (!authorization) {
            throw new ApiError(401, 'Bạn chưa đăng nhập');
        }

        const token = String(authorization).split(' ')[1];
        const decoded = verifyToken(token);
        const account = await accountService.getAccountById(String(decoded.accountId));

        if (!account) {
            throw new ApiError(404, 'Tài khoản không tồn tại');
        }

        if (account.data.tokenVersion !== decoded.tokenVersion) {
            throw new ApiError(401, 'Phiên đăng nhập đã hết hạn');
        }

        const userRole = await accountRole.getAccountRoleByAccountId(String(account.data._id));
        const role = (await roleService.getRoleById(userRole.roleId)).data;

        req.users = {
            user: account.data,
            roles: role.name,
        };
        next();
    },
);

export const authenticationSocket = async (socket: Socket, next: () => void): Promise<void> => {
    try {
        const token = (socket.handshake.auth?.token || socket.handshake.query?.token) as string;
        logger.info(`[SOCKET] New connection attempt from ${socket.id}`);

        if (!token) {
            logger.warn(`[SOCKET] Authentication failed for ${socket.id}: No token provided`);
            socket.emit('unauthorized', {
                message: 'Bạn chưa đăng nhập hoặc token không hợp lệ',
            });
            socket.disconnect(true);
            return;
        }

        const decoded = verifyToken(token);
        const account = await accountService.getAccountById(String(decoded.accountId));

        if (!account) {
            logger.warn(`[SOCKET] Authentication failed for ${socket.id}: Account not found for ID ${decoded.accountId}`);
            socket.emit('unauthorized', {
                message: 'Tài khoản không tồn tại',
            });
            socket.disconnect(true);
            return;
        }

        socket.data.user = account.data;
        await socketService.register(socket, account.data);
        logger.info(`[SOCKET] Connection authenticated: ${socket.id} (User: ${account.data._id})`);
        next();
    } catch (error) {
        logger.error(`[SOCKET] Authentication error for ${socket.id}:`, error);
        socket.emit('unauthorized', {
            message: 'Xác thực thất bại',
        });
        socket.disconnect(true);
        return;
    }
};
