            for (const r of routeList) {
                if (r.method.toUpperCase() !== currentMethod) continue;

                const isDynamic = r.route.includes(':') || r.route.includes('*');

                if (matchPath(r.route, currentPath)) {
                    const permission = `${moduleName}.${actionName}`;

                    if (!isDynamic) {
                        exactMatch = permission;
                    } else if (!dynamicMatch) {
                        dynamicMatch = permission;
                    }
                }
            }
        }
