import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import DepartmentModel from './department.model';
import { ApiError } from '@common/utils/ApiError';
import {
    IDepartmentFilter,
    IDepartmentFilterGetOne,
    IDepartmentPayload,
    IDepartments,
} from '@common/interfaces/department.interface';
import { PipelineStage, QueryFilter } from 'mongoose';

export class DepartmentService {
    public async createDepartment(payload: IDepartmentPayload): Promise<IApiResponse<IDepartments>> {
        const exitedDepartmentName = await DepartmentModel.findOne({ name: payload.name });
        if (exitedDepartmentName) {
            throw new ApiError(400, 'Tên phòng ban đã tồn tại');
        }
        const exitedDepartmentCode = await DepartmentModel.findOne({ code: payload.code });
        if (exitedDepartmentCode) {
            throw new ApiError(400, 'Mã của phòng ban đã tồn tại');
        }
        const newDepartment = await DepartmentModel.create(payload);
        return {
            success: true,
            message: 'Tạo phòng ban thành công',
            data: newDepartment,
        };
    }

    public async getOneDepartment(filter: IDepartmentFilterGetOne): Promise<IApiResponse<IDepartments>> {
        const record = await DepartmentModel.findOne(filter);
        if (!record) {
            return {
                success: false,
                message: 'Không tìm thấy phòng ban',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã thấy phòng ban',
            data: record,
        };
    }

    public async getDepartmentsByFilter(filter: IDepartmentFilter): Promise<IPaginatedResponse<IDepartments>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IDepartmentFilter> = {};
        if (filter.name) {
            const name = filter.name.normalize('NFC');
            query.$or = [
                {
                    name: {
                        $regex: `.*${name}.*`,
                        $options: 'i',
                    },
                },
                {
                    code: {
                        $regex: `.*${name}.*`,
                        $options: 'i',
                    },
                },
            ];
        }
        if (filter.code) {
            query.code = {
                $regex: `.*${filter.code}.*`,
                $options: 'i',
            };
        }
        if (filter.status) {
            query.status = filter.status;
        }
        if (filter.managerId) {
            query.managerId = filter.managerId;
        }
        const aggregateQuery: PipelineStage[] = [
            { $match: query },
            {
                $lookup: {
                    from: 'departments',
                    localField: 'parentId',
                    foreignField: '_id',
                    as: 'department',
                },
            },
            {
                $lookup: {
                    from: 'employees',
                    localField: 'managerId',
                    foreignField: '_id',
                    as: 'employee',
                },
            },
            {
                $unwind: {
                    path: '$department',
                    preserveNullAndEmptyArrays: true,
                },
            },
            {
                $unwind: {
                    path: '$employee',
                    preserveNullAndEmptyArrays: true,
                },
            },
        ];

        const [records, docCounter] = await Promise.all([
            DepartmentModel.aggregate(aggregateQuery)
                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            DepartmentModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách phòng ban thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getDepartmentById(id: string): Promise<IApiResponse<IDepartments>> {
        const record = await DepartmentModel.findById(id);
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy phòng ban này');
        }
        return {
            success: true,
            message: 'Đã thấy phòng ban',
            data: record,
        };
    }

    public async updateDepartment(id: string, payload: IDepartmentPayload): Promise<IApiResponse<IDepartments>> {
        if (payload.name) {
