        const shift = await ShiftModel.findByIdAndUpdate(id, payload, { new: true });
        if (!shift) {
            throw new ApiError(400, 'Ca làm việc không tồn tại');
        }
        return {
            success: true,
            message: 'Cập nhật thông tin ca làm việc thành công',
