                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã thấy setting',
            data: record,
        };
    }

    public async getGlobalSettingByFilter(filter: IGlobalSettingFilter): Promise<IPaginatedResponse<IGlobalSettings>> {
