                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            GlobalSettingModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách setting thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getGlobalSettingById(id: string): Promise<IApiResponse<IGlobalSettings>> {
