        const globalSetting = await GlobalSettingModel.findByIdAndUpdate(id, payload);
        if (!globalSetting) {
            throw new ApiError(400, 'Setting không tồn tại');
        }
        return {
            success: true,
            message: 'Cập nhật thông tin setting thành công',
            data: globalSetting,
        };
    }

    public async deleteGlobalSetting(id: string): Promise<IApiResponse<IGlobalSettings>> {
        const globalSetting = await GlobalSettingModel.findByIdAndDelete(id);
        if (!globalSetting) {
            throw new ApiError(400, 'Setting không tồn tại');
        }
        return {
            success: true,
            message: 'Xóa setting thành công',
            data: globalSetting,
        };
