import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import { ApiError } from '@common/utils/ApiError';
import PayrollModel from './payroll.model';
import { QueryFilter } from 'mongoose';
import { IPayroll, IPayrollFilter, IPayrollFilterGetOne, IPayrollPayload } from '@common/interfaces/payroll.interface';

export class PayrollService {
    public async createPayroll(payload: IPayrollPayload): Promise<IApiResponse<IPayroll>> {
        const newDeductions = await PayrollModel.create(payload);
        return {
            success: true,
            message: 'Tạo bảng lương thành công',
            data: newDeductions,
        };
    }

    public async getOnePayroll(filter: IPayrollFilterGetOne): Promise<IApiResponse<IPayroll>> {
        const record = await PayrollModel.findOne(filter);
        if (!record) {
            return {
                success: false,
                message: 'Không tìm thấy bảng lương',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã thấy bảng lương',
            data: record,
        };
    }

    public async getPayrollByFilter(filter: IPayrollFilter): Promise<IPaginatedResponse<IPayroll>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IPayrollFilter> = {};

        if (filter.employeeId) {
            query.employeeId = filter.employeeId;
        }
        if (filter.contractId) {
            query.contractId = filter.contractId;
        }
        if (filter.code) {
            query.code = filter.code;
        }
        if (filter.year) {
            query.year = filter.year;
        }
        if (filter.month) {
            query.month = filter.month;
        }
        if (filter.totalStandardDays) {
            query.totalStandardDays = filter.totalStandardDays;
        }
        if (filter.actualWorkDays) {
            query.actualWorkDays = filter.actualWorkDays;
        }
        if (filter.totalOTHours) {
            query.totalOTHours = filter.totalOTHours;
        }
        if (filter.grossSalary) {
            query.grossSalary = filter.grossSalary;
        }
        if (filter.netSalary) {
            query.netSalary = filter.netSalary;
        }
        if (filter.status) {
            query.status = filter.status;
        }

        const aggregateQuery = [{ $match: query }];
        const [records, docCounter] = await Promise.all([
            PayrollModel.aggregate(aggregateQuery)
                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            PayrollModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách bảng lương thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getPayrollById(id: string): Promise<IApiResponse<IPayroll>> {
        const record = await PayrollModel.findById(id);
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy bảng lương này');
        }
        return {
            success: true,
            message: 'Đã thấy bảng lương',
            data: record,
        };
    }

    public async updatePayrollById(id: string, payload: IPayrollPayload): Promise<IApiResponse<IPayroll>> {
        const deductions = await PayrollModel.findByIdAndUpdate(id, payload, { new: true });
        if (!deductions) {
            throw new ApiError(404, 'Bảng lương không tồn tại');
        }
        return {
            success: true,
            message: 'Cập nhật thông tin bảng lương thành công',
            data: deductions,
        };
    }

    public async deletePayrollById(id: string): Promise<IApiResponse<IPayroll>> {
        const deductions = await PayrollModel.findByIdAndDelete(id);
        if (!deductions) {
            throw new ApiError(404, 'Bảng lương không tồn tại');
        }
        return {
            success: true,
            message: 'Xóa bảng lương thành công',
            data: deductions,
        };
    }
}
