import { IApiResponse, IPaginatedResponse } from '@common/interfaces/response.interface';
import GlobalSettingModel from './globalSetting.model';
import { ApiError } from '@common/utils/ApiError';
import {
    IGlobalSettingFilter,
    IGlobalSettingFilterGetOne,
    IGlobalSettingPayload,
    IGlobalSettings,
} from '@common/interfaces/globalSetting.interface';
import { QueryFilter } from 'mongoose';

export class GlobalSettingService {
    public async createGlobalSetting(payload: IGlobalSettingPayload): Promise<IApiResponse<IGlobalSettings>> {
        const exitedGlobalSettingKey = await GlobalSettingModel.findOne({ key: payload.key });
        if (exitedGlobalSettingKey) {
            throw new ApiError(400, 'Key setting đã tồn tại');
        }
        const newGlobalSetting = await GlobalSettingModel.create(payload);
        return {
            success: true,
            message: 'Tạo setting thành công',
            data: newGlobalSetting,
        };
    }

    public async getOneGlobalSetting(filter: IGlobalSettingFilterGetOne): Promise<IApiResponse<IGlobalSettings>> {
        const record = await GlobalSettingModel.findOne(filter);
        if (!record) {
            return {
                success: false,
                message: 'Không tìm thấy setting',
                data: null,
            };
        }
        return {
            success: true,
            message: 'Đã thấy setting',
            data: record,
        };
    }

    public async getGlobalSettingByFilter(filter: IGlobalSettingFilter): Promise<IPaginatedResponse<IGlobalSettings>> {
        const limit = filter.limit || 10;
        const page = filter.page || 1;
        const query: QueryFilter<IGlobalSettingFilter> = {};
        if (filter.key) {
            // const key = filter.key.normalize('NFC');
            query.key = {
                $regex: `.*${filter.key}.*`,
                $options: 'i',
            };
        }
        if (filter.value) {
            query.value = {
                $regex: `.*${filter.value}.*`,
                $options: 'i',
            };
        }
        if (filter.status) {
            query.status = filter.status;
        }

        const aggregateQuery = [{ $match: query }];
        const [records, docCounter] = await Promise.all([
            GlobalSettingModel.aggregate(aggregateQuery)
                .sort({ createdAt: -1 })
                .skip((page - 1) * limit)
                .limit(limit),
            GlobalSettingModel.aggregate([...aggregateQuery, { $count: 'count' }]),
        ]);
        const count = docCounter[0]?.count || 0;

        return {
            data: records,
            success: true,
            message: 'Lấy danh sách setting thành công',
            meta: {
                totalItems: count,
                itemCount: records.length,
                itemsPerPage: limit,
                totalPages: Math.ceil(count / limit),
                currentPage: page,
            },
        };
    }

    public async getGlobalSettingById(id: string): Promise<IApiResponse<IGlobalSettings>> {
        const record = await GlobalSettingModel.findById(id);
        if (!record) {
            throw new ApiError(404, 'Không tìm thấy setting này');
        }
        return {
            success: true,
            message: 'Đã thấy setting',
            data: record,
        };
    }

    public async updateGlobalSetting(
        id: string,
        payload: IGlobalSettingPayload,
    ): Promise<IApiResponse<IGlobalSettings>> {
        if (payload.key) {
            const exitedGlobalSettingKey = await GlobalSettingModel.findOne({ key: payload.key, _id: { $ne: id } });
            if (exitedGlobalSettingKey) {
                throw new ApiError(400, 'Key setting đã tồn tại');
            }
        }

        const globalSetting = await GlobalSettingModel.findByIdAndUpdate(id, payload);
        if (!globalSetting) {
            throw new ApiError(400, 'Setting không tồn tại');
        }
        return {
            success: true,
            message: 'Cập nhật thông tin setting thành công',
            data: globalSetting,
        };
    }

    public async deleteGlobalSetting(id: string): Promise<IApiResponse<IGlobalSettings>> {
        const globalSetting = await GlobalSettingModel.findByIdAndDelete(id);
        if (!globalSetting) {
            throw new ApiError(400, 'Setting không tồn tại');
        }
        return {
            success: true,
            message: 'Xóa setting thành công',
            data: globalSetting,
        };
    }
}
