import express, { Application } from 'express';
import cors from 'cors';
import swaggerUi from 'swagger-ui-express';
import YAML from 'yamljs';
import cookieParser from 'cookie-parser';

import { errorHandler } from './common/middlewares/error.middleware';
import { trimRequest } from './common/middlewares/trim.middleware';
import router from '@common/routes';
import { FE_SERVER, NODE_ENV } from '@common/config/environment';
import { pingDatabase } from '@common/config/database';

const app: Application = express();

const feURLs = FE_SERVER?.split(',').map((h) => h.trim()) || [];

app.use(
    cors({
        origin: NODE_ENV === 'development' ? true : feURLs.length > 0 ? feURLs : false,
        credentials: true,
    }),
);
app.use(cookieParser());
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.use(trimRequest);
const swaggerDocument = YAML.load('swagger.yaml');

app.use('/docs', swaggerUi.serve, swaggerUi.setup(swaggerDocument));
app.get('/health', async (req, res) => {
    const pingDB = await pingDatabase();
    if (!pingDB) {
        res.status(503).send('Service Unavailable');
    }
    res.status(200).send('OK');
});

// Routes
export const API_PREFIX: string = '/api/v1';
app.use(API_PREFIX, router);

// error handler
app.use(errorHandler);

export default app;

